PyDoc_STRVAR(__pyx_doc_11moleculekit_6kdtree_8_ckdtree_7cKDTree_12query_pairs, "\n        query_pairs(self, r, p=2.0, eps=0.0, output_type='set')\n\n        Find all pairs of points in `self` whose distance is at most r.\n\n        Parameters\n        ----------\n        r : positive float\n            The maximum distance.\n        p : float, optional\n            Which Minkowski norm to use.  ``p`` has to meet the condition\n            ``1 <= p <= infinity``.\n            A finite large p may cause a ValueError if overflow can occur.\n        eps : float, optional\n            Approximate search.  Branches of the tree are not explored\n            if their nearest points are further than ``r/(1+eps)``, and\n            branches are added in bulk if their furthest points are nearer\n            than ``r * (1+eps)``.  `eps` has to be non-negative.\n        output_type : str, optional\n            Choose the output container, 'set' or 'ndarray'. Default: 'set'\n\n        Returns\n        -------\n        results : set or ndarray\n            Set of pairs ``(i,j)``, with ``i < j``, for which the corresponding\n            positions are close. If output_type is 'ndarray', an ndarray is\n            returned instead of a set.\n\n        Examples\n        --------\n        You can search all pairs of points in a kd-tree within a distance:\n\n        >>> import matplotlib.pyplot as plt\n        >>> import numpy as np\n        >>> from scipy.spatial import cKDTree\n        >>> rng = np.random.default_rng()\n        >>> points = rng.random((20, 2))\n        >>> plt.figure(figsize=(6, 6))\n        >>> plt.plot(points[:, 0], points[:, 1], \"xk\", markersize=14)\n        >>> kd_tree = cKDTree(points)\n        >>> pairs = kd_tree.query_pairs(r=0.2)\n        >>> for (i, j) in pairs:\n        ...     plt.plot([points[i, 0], points[j, 0]],\n        ...             [points[i, 1], points[j, 1]], \"-r\")\n        >>> plt.show()\n\n        ");
static PyMethodDef __pyx_mdef_11moleculekit_6kdtree_8_ckdtree_7cKDTree_13query_pairs = {"query_pairs", (PyCFunction)(void(*)(void))(__Pyx_PyCFunction_FastCallWithKeywords)__pyx_pw_11moleculekit_6kdtree_8_ckdtree_7cKDTree_13query_pairs, __Pyx_METH_FASTCALL|METH_KEYWORDS, __pyx_doc_11moleculekit_6kdtree_8_ckdtree_7cKDTree_12query_pairs};
